import{_ as r,o as t,c as a,a0 as i}from"./chunks/framework.BWpMpcZ2.js";const g=JSON.parse('{"title":"margin","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),n={name:"index.md"};function s(o,e,l,c,h,u){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="margin" tabindex="-1">margin <a class="header-anchor" href="#margin" aria-label="Permalink to &quot;margin&quot;">​</a></h1><p><em>Minimalist, Local-First, AI-Assisted Markdown Editor.</em></p><p>margin is an open-source AI editor designed for writers who work in markdown. Whether you&#39;re drafting a novel, a technical guide, a screenplay, or a research paper, margin helps you write with AI assistance -- entirely on your own machine if you prefer.</p><h3 id="what-makes-margin-different" tabindex="-1">What makes margin different? <a class="header-anchor" href="#what-makes-margin-different" aria-label="Permalink to &quot;What makes margin different?&quot;">​</a></h3><ul><li><strong>Local-First</strong>: Use local LLMs (Ollama, LM Studio) for full privacy. No data leaves your computer.</li><li><strong>Cloud-Ready</strong>: Also works with OpenAI, Anthropic, or any OpenAI-compatible API -- configure everything from the settings UI.</li><li><strong>Dual-Agent AI</strong>: A Planner agent reads your workspace context (characters, style guides, world notes), then a Writer agent generates prose that fits your narrative. No generic AI slop.</li><li><strong>Workspace-Oriented</strong>: Organize your project into folders (chapters, characters, styles, lore). The AI understands your structure.</li><li><strong>Privacy-First</strong>: Your content stays in your workspace. No telemetry, no tracking, no cloud dependency unless you choose it.</li></ul><h3 id="sections" tabindex="-1">Sections <a class="header-anchor" href="#sections" aria-label="Permalink to &quot;Sections&quot;">​</a></h3><ul><li><a href="./getting-started.html">Getting Started</a> -- System requirements, installation, and first launch.</li><li><a href="./configuration/general.html">Configuration</a> -- All settings explained: workspace, appearance, editor, context, endpoints.</li><li><a href="./writing-guide.html">Writing Guide</a> -- How AI assist works, character profiles, tone presets, manifests, and custom prompts.</li></ul><h3 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h3><p>The AI Assist system is an evolving first version. Future improvements planned include:</p><ul><li>Paragraph-level and document-level indexing for larger context windows</li><li>Smarter context selection heuristics</li><li>Diff previews before applying replacements</li><li>More granular control over which reference files are included per request</li></ul><h3 id="quick-links" tabindex="-1">Quick Links <a class="header-anchor" href="#quick-links" aria-label="Permalink to &quot;Quick Links&quot;">​</a></h3><ul><li><strong>GitHub</strong>: <a href="https://github.com/prxshetty/margin" target="_blank" rel="noreferrer">github.com/prxshetty/margin</a></li><li><strong>Report an Issue</strong>: <a href="https://github.com/prxshetty/margin/issues" target="_blank" rel="noreferrer">github.com/prxshetty/margin/issues</a></li></ul>',12)])])}const m=r(n,[["render",s]]);export{g as __pageData,m as default};
